INSERT INTO `problem_file` VALUES (15,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_http_methods\nimport json\n\nfrom django.views.decorators.http import require_GET\n\n@require_GET\ndef remove_chip(request):\n    status = \"REMOVE\"\n    return JsonResponse({\n        \"status\": status\n    })','BACKEND','2026-01-30 12:09:17.000000','/chip/views.py','SOURCE','F',10,'2026-01-30 12:09:17.000000'),(16,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    path(\'remove/\', views.remove_chip, name=\'remove_chip\'),\n]','BACKEND','2026-01-30 12:09:17.000000','/chip/urls.py','SOURCE','F',10,'2026-01-30 12:09:17.000000'),(17,'from django.contrib import admin\nfrom django.urls import path, include\n\nurlpatterns = [\n    path(\'admin/\', admin.site.urls),\n    path(\'api/chip/\', include(\'chip.urls\')),\n]','BACKEND','2026-01-30 12:09:17.000000','/config/urls.py','SOURCE','F',10,'2026-01-30 12:09:17.000000'),(18,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n메인 AI \'히기에이아\'의 오류 틈을 타, 칩 제거 요청을 서버에 전달해야 한다.\n\nPOST /api/chip/remove 를 호출하면 서버가 칩 상태를 \"REMOVED\"로 바꾸고 성공 메시지를 반환해야 한다.\n\n## ? 기대 응답\njson\n{\n  \"status\": \"REMOVED\",\n  \"message\": \"칩 제거 완료\"\n}\n','BACKEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',10,'2026-01-30 12:09:17.000000'),(19,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_POST\nimport uuid\n\n@require_POST\ndef steal_token(request):\n    res = issue()\n    return JsonResponse(res)\n\ndef issue():\n    return {\n        \"role\": \"ADMIN\",\n        \"adminToken\": str(uuid.uuid4())\n    }','BACKEND','2026-01-30 12:09:17.000000','/admin_api/views.py','SOURCE','F',11,'2026-01-30 12:09:17.000000'),(20,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    path(\'steal-token/\', views.steal_token, name=\'steal_token\'),\n]','BACKEND','2026-01-30 12:09:17.000000','/admin_api/urls.py','SOURCE','F',11,'2026-01-30 12:09:17.000000'),(21,'from django.contrib import admin\nfrom django.urls import path, include\n\nurlpatterns = [\n    path(\'admin/\', admin.site.urls),\n    path(\'api/admn/\', include(\'admin_api.urls\')),\n]','BACKEND','2026-01-30 12:09:17.000000','/config/urls.py','SOURCE','F',11,'2026-01-30 12:09:17.000000'),(22,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n프론트엔드에서 관리자 권한 요청 버튼 클릭 시, 백엔드에서 adminToken을 발급받아야 한다.\n\nPOST /api/admin/steal-token 를 호출하면 서버가 관리자 토큰을 생성하여 반환해야 한다.\n\n## ? 실행 결과\n{\n  \"role\": \"ADMIN\",\n  \"adminToken\": \"7b79ab1e-8325-4d00-8d61-9b7a9e462e50\"\n}\n','BACKEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',11,'2026-01-30 12:09:17.000000'),(23,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_POST\nfrom django.views.decorators.csrf import csrf_exempt\nimport json\n\n@csrf_exempt\n@require_POST\ndef verify_circuit(request):\n    try:\n        data = json.loads(request.body)\n        switches = data.get(\'switches\', [])\n        \n        open_status = (switches[0] == True and \n                      switches[1] == True and \n                      switches[2] == True)\n        \n        message = \"비상 봉쇄 해제\" if open_status else \"프로토콜 유지: 회로 불일치\"\n        \n        return JsonResponse({\n            \"open\": open_status,\n            \"message\": message\n        })\n    except Exception as e:\n        return JsonResponse({\n            \"open\": False,\n            \"message\": \"오류 발생\"\n        }, status=400)\n','BACKEND','2026-01-30 12:09:17.000000','/door/views.py','SOURCE','F',12,'2026-01-30 12:09:17.000000'),(24,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    path(\'verify-circuit/\', views.verify_circuit, name=\'verify_circuit\'),\n]','BACKEND','2026-01-30 12:09:17.000000','/door/urls.py','SOURCE','F',12,'2026-01-30 12:09:17.000000'),(25,'from django.contrib import admin\nfrom django.urls import path, include\n\nurlpatterns = [\n    path(\'admin/\', admin.site.urls),\n    path(\'api/door/\', include(\'door.urls\')),\n]','BACKEND','2026-01-30 12:09:17.000000','/config/urls.py','SOURCE','F',12,'2026-01-30 12:09:17.000000'),(26,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n프론트엔드에서 회로 조작 버튼을 누르면 백엔드로 패턴을 전송하고, 검증 결과에 따라 출구 상태를 업데이트해야 한다.\n\nPOST /api/door/verify-circuit 에 올바른 패턴 [true, false, true]을 전송하면 비상 봉쇄가 해제되어야 한다.\n\n## ? 응답 (성공)\n{\n  \"open\": true,\n  \"message\": \"비상 봉쇄 해제\"\n}','BACKEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',12,'2026-01-30 12:09:17.000000'),(27,'import React from \'react\';\nimport axios from \'axios\';\n\nfunction ChipControl() {\n  const chipStatus = \'INSTALLED\';\n\n  const removeChip = () => {\n    axios.post(\'/api/chip/remove\')\n      .then(res => {\n        chipStatus = \'REMOVED\';\n      });\n  };\n\n  return (\n    <div>\n      {chipStatus === \'INSTALLED\' && (\n        <>\n          <p>실험칩 상태: {chipStatus}</p>\n          <button onClick={removeChip}>비활성화</button>\n        </>\n      )}\n    </div>\n  );\n}\n\nexport default ChipControl;','FRONTEND','2026-01-30 12:09:17.000000','/frontend_react/src/components/ChipControl.jsx','SOURCE','F',13,'2026-01-30 12:09:17.000000'),(28,'package com.example.demo.chip;\n\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/chip\")\npublic class ChipController {\n\n    private final ChipService chipService;\n\n    public ChipController(ChipService chipService) {\n        this.chipService = chipService;\n    }\n\n    @GetMapping(\"/remove\")\n    public ResponseEntity<ChipRemoveRes> removeChip() {\n        ChipRemoveRes res = chipService.removeChip();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipController.java','SOURCE','F',13,'2026-01-30 12:09:17.000000'),(29,'package com.example.demo.chip;\n\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class ChipService {\n\n    public ChipRemoveRes removeChip() {\n        ChipRemoveRes res = new ChipRemoveRes();\n        res.setStatus(\"REMOVED\");\n        res.setMessage(\"칩 제거 완료\");\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipService.java','SOURCE','F',13,'2026-01-30 12:09:17.000000'),(30,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n프론트엔드에서 칩 상태를 표시하고, 백엔드 API를 호출하여 실험칩을 비활성화해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 화면이 렌더링되지 않음\n- 백엔드: POST 요청이 405 에러로 실패\n- 칩 비활성화 버튼이 작동하지 않음\n\n## ? 요구사항\n- 프론트엔드에서 칩 상태를 정상 표시하시오\n- 백엔드 API가 POST 요청을 처리하도록 수정하시오\n- 비활성화 버튼 클릭 시 API 호출이 성공하도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',13,'2026-01-30 12:09:17.000000'),(31,'import React, { useState } from \'react\';\nimport AdminPanel from \'./AdminPanel\';\n\nfunction AdminAuth() {\n  const isAdmin = false;\n  const [token, setToken] = useState(\'\');\n\n  return (\n    <div>\n      <AdminPanel isadmin={isAdmin} onTokenReceived={setToken} />\n      {token && <p>토큰: {token}</p>}\n    </div>\n  );\n}\n\nexport default AdminAuth;','FRONTEND','2026-01-30 12:09:17.000000','/frontend_react/src/components/AdminAuth.jsx','SOURCE','F',14,'2026-02-02 10:20:33.000000'),(32,'import React from \'react\';\nimport axios from \'axios\';\n\nfunction AdminPanel({ isAdmin, onTokenReceived }) {\n  const requestaccess = () => {\n    axios.post(\'/api/admin/steal-token\')\n      .then(res => {\n        onTokenReceived(res.data.adminToken);\n      });\n  };\n\n  return (\n    <>\n      {isAdmin && (\n        <button onClick={requestAccess}>\n          관리자 권한 요청\n        </button>\n      )}\n    </>\n  );\n}\n\nexport default AdminPanel;','FRONTEND','2026-01-30 12:09:17.000000','/frontend_react/src/components/AdminPanel.jsx','SOURCE','F',14,'2026-01-30 12:09:17.000000'),(33,'package com.example.demo.admin;\n\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/admn\")\n@RequiredArgsConstructor\npublic class AdminController {\n\n    private final AdminService adminService;\n\n    @PostMapping(\"/steal-token\")\n    public ResponseEntity<AdminTokenRes> stealToken() {\n        AdminTokenRes res = adminService.generateToken();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminController.java','SOURCE','F',14,'2026-02-02 10:20:33.000000'),(34,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n프론트엔드에서 관리자 권한 요청 버튼 클릭 시, 백엔드에서 adminToken을 발급받아야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 버튼 클릭 시 아무 반응 없음\n- 백엔드: 404 Not Found 에러 발생\n- 관리자 토큰이 발급되지 않음\n\n## ? 요구사항\n- 프론트엔드에서 버튼이 정상 동작하도록 수정하시오\n- 백엔드 URL 패턴과 함수명을 수정하시오\n- 토큰이 정상적으로 발급되고 화면에 표시되도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',14,'2026-02-02 10:20:33.000000'),(35,'import React, { useState, useEffect } from \'react\';\nimport axios from \'axios\';\n\nfunction DoorControl() {\n  const [doorStatus, setDoorStatus] = useState(\'LOCKED\');\n\n  useEffect(() => {\n    if (doorStatus === \'UNLOCKED\') {\n      console.log(\'출구 개방\');\n    }\n  });\n\n  const unlock = () => {\n    const pattern = [true, false, true];\n\n    axios.post(\'/api/door/verify-circuit\', { pattern })\n      .then(res => {\n        if (res.data.open) {\n          setDoorStatus(\'UNLOCKED\');\n        }\n      });\n  };\n\n  return (\n    <div>\n      <p>출구 상태: {doorStatus}</p>\n      <button onClick={unlock()}>회로 조작</button>\n    </div>\n  );\n}\n\nexport default DoorControl;','FRONTEND','2026-01-30 12:09:17.000000','/frontend_react/src/components/DoorControl.jsx','SOURCE','F',15,'2026-01-30 12:09:17.000000'),(36,'package com.example.demo.door;\n\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/door\")\n@RequiredArgsConstructor\npublic class DoorController {\n\n    private final DoorService doorService;\n\n    @PostMapping(\"/verify-circuit\")\n    public ResponseEntity<DoorVerifyRes> verifyCircuit() {\n        DoorVerifyRes res = doorService.verifyPattern();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/DoorController.java','SOURCE','F',15,'2026-01-30 12:09:17.000000'),(37,'package com.example.demo.door;\n\nimport org.springframework.stereotype.Service;\nimport java.util.List;\n\n@Service\npublic class DoorService {\n\n    public DoorVerifyRes verifyPattern(List<Boolean> switches) {\n        DoorVerifyRes res = new DoorVerifyRes();\n\n        List<Boolean> correctPattern = List.of(true, false, true);\n        boolean isCorrect = switches = correctPattern;\n\n        if (isCorrect) {\n            res.setOpen(true);\n            res.setMessage(\"비상 봉쇄 해제\");\n        } else {\n            res.setOpen(false);\n            res.setMessage(\"패턴 불일치\");\n        }\n\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/DoorService.java','SOURCE','F',15,'2026-01-30 12:09:17.000000'),(38,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n프론트엔드에서 회로 조작 버튼을 누르면 백엔드로 패턴을 전송하고, 검증 결과에 따라 출구 상태를 업데이트해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 무한 렌더링 발생 및 버튼 즉시 실행\n- 백엔드: 패턴 검증이 항상 실패하거나 500 에러\n- 출구 상태가 업데이트되지 않음\n\n## ? 요구사항\n- 프론트엔드 무한 렌더링을 해결하시오\n- 백엔드 패턴 검증 로직을 수정하시오\n- 올바른 패턴 전송 시 출구가 열리도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',15,'2026-01-30 12:09:17.000000'),(39,'<template>\n  <div v-if=\"chipStatus === \'INSTALLED\'\">\n    <p>실험칩 상태: {{ chipStatus }}</p>\n    <button @click=\"removeChip\">비활성화</button>\n  </div>\n</template>\n\n<script setup>\nimport { ref } from \'vue\'\nimport axios from \'axios\'\n\nconst chipStatus = ref(\'INSTALLED\')\n\nfunction removeChip() {\n  axios.post(\'/api/chip/remove\')\n    .then(() => {\n      chipStatus = \'REMOVED\'\n    })\n}\n</script>','FRONTEND','2026-01-30 12:09:17.000000','/frontend_vue/src/components/ChipControl.vue','SOURCE','F',16,'2026-01-30 12:09:17.000000'),(40,'package com.example.demo.chip;\n\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/chip\")\npublic class ChipController {\n\n    private final ChipService chipService;\n\n    public ChipController(ChipService chipService) {\n        this.chipService = chipService;\n    }\n\n    @GetMapping(\"/remove\")\n    public ResponseEntity<ChipRemoveRes> removeChip() {\n        ChipRemoveRes res = chipService.removeChip();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipController.java','SOURCE','F',16,'2026-01-30 12:09:17.000000'),(41,'package com.example.demo.chip;\n\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class ChipService {\n\n    public ChipRemoveRes removeChip() {\n        ChipRemoveRes res = new ChipRemoveRes();\n        res.setStatus(\"REMOVED\");\n        res.setMessage(\"칩 제거 완료\");\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipService.java','SOURCE','F',16,'2026-01-30 12:09:17.000000'),(42,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n프론트엔드에서 칩 상태를 표시하고, 백엔드 API를 호출하여 실험칩을 비활성화해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 화면이 렌더링되지 않음\n- 백엔드: POST 요청이 405 에러로 실패\n- 칩 비활성화 버튼이 작동하지 않음\n\n## ? 요구사항\n- 프론트엔드에서 칩 상태를 정상 표시하시오\n- 백엔드 API가 POST 요청을 처리하도록 수정하시오\n- 비활성화 버튼 클릭 시 API 호출이 성공하도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',16,'2026-01-30 12:09:17.000000'),(43,'<template>\n  <div>\n    <AdminPanel :isadmin=\"isAdmin\" @token-received=\"setToken\" />\n    <p v-if=\"token\">토큰: {{ token }}</p>\n  </div>\n</template>\n\n<script>\nimport AdminPanel from \'./AdminPanel.vue\';\n\nexport default {\n  name: \'AdminAuth\',\n  components: {\n    AdminPanel\n  },\n  data() {\n    return {\n      isAdmin: true,\n      token: \'\'\n    };\n  },\n  methods: {\n    setToken(adminToken) {\n      this.token = adminToken;\n    }\n  }\n};\n</script>','FRONTEND','2026-01-30 12:09:17.000000','/frontend_vue/src/components/AdminAuth.vue','SOURCE','F',17,'2026-01-30 12:09:17.000000'),(44,'<template>\n  <div>\n    <button v-if=\"isAdmin\" @click=\"requestAccess\">\n      관리자 권한 요청\n    </button>\n  </div>\n</template>\n\n<script>\nimport axios from \'axios\';\n\nexport default {\n  name: \'AdminPanel\',\n  props: {\n    isAdmin: {\n      type: Boolean,\n      required: true\n    }\n  },\n  methods: {\n    requestaccess() {\n      axios.post(\'/api/admin/steal-token\')\n        .then(res => {\n          this.$emit(\'token-received\', res.data.adminToken);\n        });\n    }\n  }\n};\n</script>','FRONTEND','2026-01-30 12:09:17.000000','/frontend_vue/src/components/AdminPanel.vue','SOURCE','F',17,'2026-01-30 12:09:17.000000'),(45,'package com.example.demo.admin;\n\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/admn\")\n@RequiredArgsConstructor\npublic class AdminController {\n\n    private final AdminService adminService;\n\n    @PostMapping(\"/steal-token\")\n    public ResponseEntity<AdminTokenRes> stealToken() {\n        AdminTokenRes res = adminService.generateToken();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminController.java','SOURCE','F',17,'2026-01-30 12:09:17.000000'),(46,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n프론트엔드에서 관리자 권한 요청 버튼 클릭 시, 백엔드에서 adminToken을 발급받아야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 버튼 클릭 시 아무 반응 없음\n- 백엔드: 404 Not Found 에러 발생\n- 관리자 토큰이 발급되지 않음\n\n## ? 요구사항\n- 프론트엔드에서 버튼이 정상 동작하도록 수정하시오\n- 백엔드 URL 패턴과 함수명을 수정하시오\n- 토큰이 정상적으로 발급되고 화면에 표시되도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',17,'2026-01-30 12:09:17.000000'),(47,'<template>\n  <div>\n    <p>출구 상태: {{ doorStatus }}</p>\n    <button @click=\"unlock()\">회로 조작</button>\n  </div>\n</template>\n\n<script>\nimport axios from \'axios\';\n\nexport default {\n  name: \'DoorControl\',\n  data() {\n    return {\n      doorStatus: \'LOCKED\'\n    };\n  },\n  watch: {\n    doorStatus(newVal) {\n      if (newVal === \'UNLOCKED\') {\n        console.log(\'출구 개방\');\n        this.doorStatus = \'UNLOCKED\';\n      }\n    }\n  },\n  methods: {\n    unlock() {\n      const pattern = [true, false, true];\n\n      axios.post(\'/api/door/verify-circuit\', { pattern })\n        .then(res => {\n          if (res.data.open) {\n            this.doorStatus = \'UNLOCKED\';\n          }\n        });\n    }\n  }\n};\n</script>','FRONTEND','2026-01-30 12:09:17.000000','/frontend_vue/src/components/DoorControl.vue','SOURCE','F',18,'2026-01-30 12:09:17.000000'),(48,'package com.example.demo.door;\n\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/door\")\n@RequiredArgsConstructor\npublic class DoorController {\n\n    private final DoorService doorService;\n\n    @PostMapping(\"/verify-circuit\")\n    public ResponseEntity<DoorVerifyRes> verifyCircuit() {\n        DoorVerifyRes res = doorService.verifyPattern();\n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/DoorController.java','SOURCE','F',18,'2026-01-30 12:09:17.000000'),(49,'package com.example.demo.door;\n\nimport org.springframework.stereotype.Service;\nimport java.util.List;\n\n@Service\npublic class DoorService {\n\n    public DoorVerifyRes verifyPattern(List<Boolean> switches) {\n        DoorVerifyRes res = new DoorVerifyRes();\n\n        List<Boolean> correctPattern = List.of(true, false, true);\n        boolean isCorrect = switches == correctPattern;\n\n        if (isCorrect) {\n            res.setOpen(true);\n            res.setMessage(\"비상 봉쇄 해제\");\n        } else {\n            res.setOpen(false);\n            res.setMessage(\"패턴 불일치\");\n        }\n\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/DoorService.java','SOURCE','F',18,'2026-01-30 12:09:17.000000'),(50,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n프론트엔드에서 회로 조작 버튼을 누르면 백엔드로 패턴을 전송하고, 검증 결과에 따라 출구 상태를 업데이트해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 무한 렌더링 발생 및 버튼 즉시 실행\n- 백엔드: 패턴 검증이 항상 실패하거나 500 에러\n- 출구 상태가 업데이트되지 않음\n\n## ? 요구사항\n- 프론트엔드 무한 렌더링을 해결하시오\n- 백엔드 패턴 검증 로직을 수정하시오\n- 올바른 패턴 전송 시 출구가 열리도록 하시오','FRONTEND','2026-01-30 12:09:17.000000','/README.md','DOC','F',18,'2026-01-30 12:09:17.000000'),(51,'import React from \'react\';\nimport axios from \'axios\';\n\nfunction ChipControl() {\n  const chipStatus = \'INSTALLED\';\n\n  const removeChip = () => {\n    axios.post(\'/api/chip/remove\')\n      .then(() => {\n        // 문제: const 변수에 값 재할당 시도 및 useState 미사용\n        chipStatus = \'REMOVED\';\n      });\n  };\n\n  return (\n    <div>\n      {chipStatus === \'INSTALLED\' && (\n        <>\n          <p>실험칩 상태: {chipStatus}</p>\n          <button onClick={removeChip}>비활성화</button>\n        </>\n      )}\n    </div>\n  );\n}\n\nexport default ChipControl;','FRONTEND','2026-01-30 12:09:17.000000','/frontend_react/src/components/ChipControl.jsx','SOURCE','F',19,'2026-01-30 12:09:17.000000'),(52,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_http_methods\n\n@require_http_methods([\"GET\"])\ndef remove_chip(request):\n    response = {}\n    # 문제: dict 객체에 속성(.) 방식으로 접근 시도\n    response.status = \"REMOVED\"\n    response[\'message\'] = \"칩 제거 완료\"\n    return JsonResponse(response)','BACKEND','2026-01-30 12:09:17.000000','/backend_django/chip/views.py','SOURCE','F',19,'2026-01-30 12:09:17.000000'),(53,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    path(\'chip/remove/\', views.remove_chip, name=\'remove_chip\'),\n]','BACKEND','2026-01-30 12:09:18.000000','/backend_django/chip/urls.py','SOURCE','F',19,'2026-01-30 12:09:18.000000'),(54,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n프론트엔드에서 칩 상태를 표시하고, 백엔드 API를 호출하여 실험칩을 비활성화해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: const 변수 재할당으로 상태 업데이트 실패\n- 백엔드: HTTP 메서드 불일치로 405 에러 발생','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',19,'2026-01-30 12:09:18.000000'),(55,'import React, { useState } from \'react\';\nimport AdminPanel from \'./AdminPanel\';\n\nfunction AdminAuth() {\n  const [isAdmin, setIsAdmin] = useState(false);\n  const [token, setToken] = useState(\'\');\n\n  return (\n    <div>\n      {/* 문제: props 이름 대소문자 불일치(isadmin) */}\n      <AdminPanel isadmin={isAdmin} onTokenReceived={setToken} />\n      {token && <p>토큰: {token}</p>}\n    </div>\n  );\n}\n\nexport default AdminAuth;','FRONTEND','2026-01-30 12:09:18.000000','/frontend_react/src/components/AdminAuth.jsx','SOURCE','F',20,'2026-01-30 12:09:18.000000'),(56,'import React from \'react\';\nimport axios from \'axios\';\n\nfunction AdminPanel({ isAdmin, onTokenReceived }) {\n  const requestaccess = () => {\n    axios.post(\'/api/admin/steal-token\')\n      .then(res => {\n        onTokenReceived(res.data.adminToken);\n      });\n  };\n\n  return (\n    <>\n      {/* 문제: @click 핸들러 함수명 대소문자 불일치(requestAccess) */}\n      {isAdmin && (\n        <button onClick={requestAccess}>\n          관리자 권한 요청\n        </button>\n      )}\n    </>\n  );\n}\n\nexport default AdminPanel;','FRONTEND','2026-01-30 12:09:18.000000','/frontend_react/src/components/AdminPanel.jsx','SOURCE','F',20,'2026-01-30 12:09:18.000000'),(57,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_POST\n\n@require_POST\ndef steal_token(request):\n    # 문제: issue_token 함수명 불일치 및 import 누락\n    token_data = issue_token()\n    return JsonResponse(token_data)','BACKEND','2026-01-30 12:09:18.000000','/backend_django/admin/views.py','SOURCE','F',20,'2026-01-30 12:09:18.000000'),(58,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    # 문제: URL 패턴 오타 (admn)\n    path(\'admn/steal-token/\', views.steal_token, name=\'steal_token\'),\n]','BACKEND','2026-01-30 12:09:18.000000','/backend_django/admin/urls.py','SOURCE','F',20,'2026-01-30 12:09:18.000000'),(59,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n프론트엔드에서 관리자 권한 요청 버튼을 표시하고, 백엔드에서 adminToken을 발급받아야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: props 대소문자 불일치, 함수명 오류로 버튼 작동 안 함\n- 백엔드: URL 패턴 오타로 404 에러 발생','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',20,'2026-01-30 12:09:18.000000'),(60,'import React, { useState, useEffect } from \'react\';\nimport axios from \'axios\';\n\nfunction DoorControl() {\n  const [doorStatus, setDoorStatus] = useState(\'LOCKED\');\n\n  // 문제: useEffect 의존성 배열 누락으로 무한 렌더링\n  useEffect(() => {\n    if (doorStatus === \'UNLOCKED\') {\n      console.log(\'출구 개방\');\n    }\n  });\n\n  const unlock = () => {\n    const pattern = [true, false, true];\n\n    axios.post(\'/api/door/verify-circuit\', { switches: pattern })\n      .then(res => {\n        if (res.data.open) {\n          setDoorStatus(\'UNLOCKED\');\n        }\n      });\n  };\n\n  return (\n    <div>\n      <p>출구 상태: {doorStatus}</p>\n      {/* 문제: onClick에 함수를 즉시 호출함() */}\n      <button onClick={unlock()}>회로 조작</button>\n    </div>\n  );\n}\n\nexport default DoorControl;','FRONTEND','2026-01-30 12:09:18.000000','/frontend_react/src/components/DoorControl.jsx','SOURCE','F',21,'2026-01-30 12:09:18.000000'),(61,'import json\nfrom django.http import JsonResponse\nfrom django.views.decorators.http import require_POST\n\n@require_POST\ndef verify_circuit(request):\n    # 문제: request 객체 자체를 파싱 (request.body 필요)\n    data = json.loads(request)\n    switches = data.get(\'switches\', [])\n\n    correct_pattern = [True, False, True]\n    # 문제: 할당 연산자(=)를 사용한 비교 로직 오류\n    is_correct = switches = correct_pattern\n\n    if is_correct:\n        return JsonResponse({\n            \'open\': True,\n            \'message\': \'비상 봉쇄 해제\'\n        })\n    else:\n        return JsonResponse({\n            \'open\': False,\n            \'message\': \'패턴 불일치\'\n        })','BACKEND','2026-01-30 12:09:18.000000','/backend_django/door/views.py','SOURCE','F',21,'2026-01-30 12:09:18.000000'),(62,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n프론트엔드에서 회로 조작 버튼을 누르면 백엔드로 패턴을 전송하고, 검증 결과에 따라 출구 상태를 업데이트해야 한다.\n\n## ❌ 현재 상황\n- 프론트엔드: useEffect 의존성 배열 누락으로 무한 렌더링 발생\n- 백엔드: JSON 파싱 오류 및 비교 연산자 오류','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',21,'2026-01-30 12:09:18.000000'),(63,'<template>\n  <div v-if=\"chipStatus === \'INSTALLED\'\">\n    <p>실험칩 상태: {{ chipStatus }}</p>\n    <button @click=\"removeChip\">비활성화</button>\n  </div>\n</template>\n\n<script setup>\nimport axios from \'axios\';\n\n// 문제: ref()를 사용하지 않아 반응성이 없음\nconst chipStatus = \'INSTALLED\';\n\nconst removeChip = () => {\n  axios.post(\'/api/chip/remove\')\n    .then(() => {\n      // 문제: const 변수에 값 재할당 시도\n      chipStatus = \'REMOVED\';\n    });\n};\n</script>','FRONTEND','2026-01-30 12:09:18.000000','/frontend_vue/src/components/ChipControl.vue','SOURCE','F',22,'2026-01-30 12:09:18.000000'),(64,'from django.http import JsonResponse\nfrom django.views.decorators.http import require_http_methods\n\n@require_http_methods([\"GET\"]) # 문제: POST 요청을 허용해야 함\ndef remove_chip(request):\n    response = {}\n    # 문제: Dictionary 객체에 속성(.) 방식으로 접근 시도\n    response.status = \"REMOVED\"\n    return JsonResponse(response)','BACKEND','2026-01-30 12:09:18.000000','/backend_django/chip/views.py','SOURCE','F',22,'2026-01-30 12:09:18.000000'),(65,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n프론트엔드에서 칩 상태를 표시하고, 백엔드 API를 호출하여 실험칩을 비활성화한다.\n\n## ❌ 현재 상황\n- 프론트엔드: 일반 변수(const) 사용으로 인한 반응성(Reactivity) 부재\n- 백엔드: HTTP 메서드 불일치로 405 에러 발생','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',22,'2026-01-30 12:09:18.000000'),(66,'<template>\n  <button v-if=\"isAdmin\" @click=\"requestAccess\">\n    관리자 권한 요청\n  </button>\n</template>\n\n<script setup>\nimport axios from \'axios\';\n\n// 문제: props/emit 이름 불일치 및 emit 사용법 오류\nconst props = defineProps([\'isAdmin\']);\nconst emit = defineEmits([\'token-received\']);\n\nconst requestAccess = () => {\n  axios.post(\'/api/admin/steal-token\')\n    .then(res => {\n      emit(\'token-received\', res.data.adminToken);\n    });\n};\n</script>','FRONTEND','2026-01-30 12:09:18.000000','/frontend_vue/src/components/AdminPanel.vue','SOURCE','F',23,'2026-01-30 12:09:18.000000'),(67,'from django.urls import path\nfrom . import views\n\nurlpatterns = [\n    # 문제: URL 경로 오타 (admn)\n    path(\'admn/steal-token/\', views.steal_token),\n]','BACKEND','2026-01-30 12:09:18.000000','/backend_django/admin/urls.py','SOURCE','F',23,'2026-01-30 12:09:18.000000'),(68,'from django.http import JsonResponse\n\ndef steal_token(request):\n    # 문제: 정의되지 않은 함수 issue_token 호출\n    token_data = issue_token()\n    return JsonResponse(token_data)','BACKEND','2026-01-30 12:09:18.000000','/backend_django/admin/views.py','SOURCE','F',23,'2026-01-30 12:09:18.000000'),(69,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n관리자 권한 요청 버튼을 표시하고, 백엔드에서 adminToken을 발급받아 화면에 출력한다.\n\n## ❌ 현재 상황\n- 프론트엔드: props / emit 이름 불일치\n- 백엔드: URL 오타로 404 발생, 함수 참조 오류','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',23,'2026-01-30 12:09:18.000000'),(70,'<template>\n  <p>출구 상태: {{ doorStatus }}</p>\n  <button @click=\"unlock()\">회로 조작</button>\n</template>\n\n<script setup>\nimport { ref } from \'vue\';\nimport axios from \'axios\';\n\nconst doorStatus = ref(\'LOCKED\');\n\nconst unlock = () => {\n  const pattern = [true, false, true];\n  axios.post(\'/api/door/verify-circuit\', { switches: pattern })\n    .then(res => {\n      if (res.data.open) doorStatus.value = \'UNLOCKED\';\n    });\n};\n</script>','FRONTEND','2026-01-30 12:09:18.000000','/frontend_vue/src/components/DoorControl.vue','SOURCE','F',24,'2026-01-30 12:09:18.000000'),(71,'import json\nfrom django.http import JsonResponse\n\ndef verify_circuit(request):\n    # 문제: request 객체 자체를 파싱 (request.body 필요)\n    data = json.loads(request)\n    correct_pattern = [True, False, True]\n    # 문제: 할당 연산자(=)를 사용한 잘못된 비교 로직\n    is_correct = (data.get(\'switches\') = correct_pattern)\n    return JsonResponse({\'open\': is_correct})','BACKEND','2026-01-30 12:09:18.000000','/backend_django/door/views.py','SOURCE','F',24,'2026-01-30 12:09:18.000000'),(72,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n회로 조작 버튼 클릭 시 패턴을 전송하고, 결과에 따라 출구 상태를 갱신한다.\n\n## ❌ 현재 상황\n- 프론트엔드 이벤트 바인딩 실수\n- 백엔드 JSON 파싱 오류\n- 비교 연산자 오사용','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',24,'2026-01-30 12:09:18.000000'),(73,'\npackage com.example.demo.chip;\n  \nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n  \n@RestController\n@RequestMapping(\"/api/chip\")\npublic class ChipController {\n	private final ChipService chipService;\n  \n	public ChipController(ChipService chipService) {\n		this.chipService = chipService;\n	}\n  \n 	@GetMapping(\"/remove\")\n 	public ResponseEntity<ChipRemoveRes> removeChip() {\n		ChipRemoveRes res = chipService.removeChip();\n        return ResponseEntity.ok(res);\n	}\n}\n','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/ChipController.java','SOURCE','F',7,'2026-01-30 12:09:18.000000'),(74,'package com.example.demo.chip;\n\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class ChipService {\n\n    public ChipRemoveRes removeChip() {\n        ChipRemoveRes res = new ChipRemoveRes();\n        res.setStatus(\"REMOVE\");\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/ChipService.java','SOURCE','F',7,'2026-01-30 12:09:18.000000'),(75,'package com.example.demo.chip;\n\nimport lombok.*;\n\npublic class ChipRemoveRes {\n    private String status;\n    private String message;\n\n    public String getMessage() {\n        return message;\n    }\n\n    public void setMessage(String message) {\n        this.message = message;\n    }\n    \n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/ChipRemoveRes.java','SOURCE','F',7,'2026-01-30 12:09:18.000000'),(76,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n메인 AI ‘히기에이아’의 오류 틈을 타, 칩 제거 요청을 서버에 전달해야 한다.\nPOST /api/chip/remove 를 호출하면 서버가 칩 상태를 “REMOVED”로 바꾸고 성공 메시지를 반환해야 한다.\n\n## ? 실행 결과\n{\n  \"status\": \"REMOVED\",\n  \"message\": \"칩 제거 완료\"\n}','BACKEND','2026-01-30 12:09:18.000000','README.md','DOC','F',7,'2026-01-30 12:09:18.000000'),(77,'package com.example.demo.chip;\n\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/admn\")\n@RequiredArgsConstructor\npublic class AdminController {\n\n    @PostMapping(\"/steal-token\")\n    public ResponseEntity<AdminTokenRes> stealToken() {\n        AdminTokenRes res = issue(); \n        return ResponseEntity.ok(res);\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/AdminController.java','SOURCE','F',8,'2026-01-30 12:09:18.000000'),(78,'package com.example.demo.chip;\nimport org.springframework.stereotype.Service;\nimport java.util.UUID;\n\n@Service\npublic class AdminService {\n\n    public AdminTokenRes issue() {\n        AdminTokenRes res = new AdminTokenRes();\n        res.setRole(\"ADMIN\");\n        res.setAdminToken(UUID.randomUUID().toString());\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/AdminService.java','SOURCE','F',8,'2026-01-30 12:09:18.000000'),(79,'package com.example.demo.chip;\n\nimport lombok.*;\n\n@Getter\n@Setter\npublic class AdminTokenRes {\n    private String role;\n    private String adminToken;\n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/AdminTokenRes.java','SOURCE','F',8,'2026-01-30 12:09:18.000000'),(80,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n중앙 서버 시스템을 조작해 관리자 권한을 얻는 API가 필요하다.\nPOST /api/admin/steal-token 호출 시 adminToken을 발급해 반환해야 한다.\n\n## ? 실행 결과\n{\n  \"role\": \"ADMIN\",\n  \"adminToken\": \"7b79ab1e-8325-4d00-8d61-9b7a9e462e50\"\n}','BACKEND','2026-01-30 12:09:18.000000','README.md','DOC','F',8,'2026-01-30 12:09:18.000000'),(81,'package com.example.demo.chip;\n\nimport lombok.*;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/door\")\npublic class DoorController {\n\n    private final DoorService doorService;\n\n    @PostMapping(\"/verify-circuit\")\n    public ResponseEntity<CircuitVerifyRes> verify(@RequestBody CircuitVerifyReq req) {\n        return ResponseEntity.ok(doorService.verify(req));\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','backend_spring/src/main/java/com/example/demo/chip/DoorController.java','SOURCE','F',9,'2026-01-30 12:09:18.000000'),(82,'package com.example.demo.chip;\n\nimport lombok.*;\n\npublic class CircuitVerifyReq {\n    private boolean[] switches;\n\n    public boolean[] getSwitches() {\n        return switches;\n    }\n\n    public void setSwitches(boolean switches) {\n        this.switches = new boolean[]{ switches };\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/chip/CircuitVerifyReq.java','SOURCE','F',9,'2026-01-30 12:09:18.000000'),(83,'package com.example.demo.chip;\n\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class DoorService {\n\n    public CircuitVerifyRes verify(CircuitVerifyReq req) {\n        boolean[] s = req.getSwitches();\n\n        boolean open = s[0] == true && s[1] == true && s[2] == true;\n\n        CircuitVerifyRes res = new CircuitVerifyRes();\n        res.setOpen(open);\n        res.setMessage(open ? \"비상 봉쇄 해제\" : \"프로토콜 유지: 회로 불일치\");\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/chip/DoorService.java','SOURCE','F',9,'2026-01-30 12:09:18.000000'),(84,'package com.example.demo.chip;\n\nimport lombok.*;\n\npublic class CircuitVerifyRes {\n    private boolean open;\n    private String message;\n\n    public boolean isOpen() { \n        return open; \n    }\n\n    public void setOpen(boolean open) { \n        this.open = open; \n    }\n\n    public String getMessage() { \n        return message; \n    }\n\n    public void setMessage(String message) { \n        this.message = message; \n    }\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/chip/CircuitVerifyRes.java','SOURCE','F',9,'2026-01-30 12:09:18.000000'),(85,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n정답 패턴 [true, false, true] 일 때 open=true를 반환하도록 수정하시오.\n\n## ? 실행 결과\n\n### 요청 (POST `/api/door/verify-circuit`)\n\n{\n  \"switches\": [true, false, true]\n}\n\n### 응답\n\n{\n    \"open\": true,\n    \"message\": \"비상 봉쇄 해제\"\n}','BACKEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',9,'2026-01-30 12:09:18.000000'),(86,'package com.example.demo.chip;\n\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Getter\n@Setter\npublic class ChipRemoveRes {\n    private String status;\n    private String message;\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipRemoveRes.java','SOURCE','F',13,'2026-02-02 00:26:31.000000'),(89,'package com.example.demo.chip;\nimport org.springframework.stereotype.Service;\nimport java.util.UUID;\n\n@Service\npublic class AdminService {\n\n    public AdminTokenRes issue() {\n        AdminTokenRes res = new AdminTokenRes();\n        res.setRole(\"ADMIN\");\n        res.setAdminToken(UUID.randomUUID().toString());\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminService.java','SOURCE','F',14,'2026-01-30 12:09:18.000000'),(90,'package com.example.demo.chip;\n\nimport lombok.*;\n\n@Getter\n@Setter\npublic class AdminTokenRes {\n    private String role;\n    private String adminToken;\n}','BACKEND','2026-01-30 12:09:18.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminTokenRes.java','SOURCE','F',14,'2026-01-30 12:09:18.000000'),(101,'<template>\n  <div class=\"console-panel\">\n    <ChipDisplay :status=\"status\" />\n    <ChipButton />\n  </div>\n</template>\n\n<script>\nimport axios from \'axios\';\nimport ChipDisplay from \'./ChipDisplay.vue\';\nimport ChipButton from \'./ChipButton.vue\';\n\nexport default {\n  name: \'ChipControl\',\n  components: {\n    ChipDisplay,\n    ChipButton\n  },\n  data() {\n    return {\n      status: \'INSTALLED\'\n    };\n  },\n  methods: {\n    handleDeactivate() {\n      axios.post(\'/api/chip/remove\')\n        .then(() => {\n          this.status = \'REMOVED\';\n        });\n    }\n  }\n};\n</script>\n','FRONTEND','2026-02-01 20:34:44.000000','/frontend_vue/src/components/ChipControl.vue','SOURCE','F',4,'2026-02-01 20:34:44.000000'),(102,'<template>\n  <div class=\"display-area\">\n    <p>보안 칩 시스템 상태: <strong>{{ chipStatus }}</strong></p>\n  </div>\n</template>\n\n<script>\nexport default {\n  name: \'ChipDisplay\',\n  props: {\n    currentStatus: {\n      type: String,\n      required: true\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/ChipDisplay.vue','SOURCE','F',4,'2026-02-01 20:34:45.000000'),(103,'<template>\n  <button class=\"action-btn\" @click=\"onDeactivate\">\n    실험칩 비활성화\n  </button>\n</template>\n\n<script>\nexport default {\n  name: \'ChipButton\',\n  props: {\n    onDeactivate: {\n      type: Function,\n      required: true\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/ChipButton.vue','SOURCE','F',4,'2026-02-01 20:34:45.000000'),(104,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n노트북의 관리 콘솔 화면이 여러 컴포넌트로 분리되어 있으나, 데이터 흐름이 끊겨 화면이 보이지 않는다.\n프론트엔드 컴포넌트 간의 연결 오류를 수정하여 실험칩 비활성화 시퀀스를 완료하라.\n\n## ? 요구사항\n1. 컴포넌트 간 현재 칩 상태가 정상 전달되도록 수정하시오.\n2. 비활성화 버튼 클릭 시 호출되는 함수가 ChipButton까지 올바르게 전달되게 하시오.\n3. 비동기 통신 성공 후 REMOVED 상태가 화면에 즉시 반영되도록 하시오.','FRONTEND','2026-02-01 20:34:45.000000','/README.md','DOC','F',4,'2026-02-01 20:34:45.000000'),(105,'<template>\n  <div class=\"admin-screen\">\n    <h2>중앙 제어 시스템</h2>\n    <AdminPanel :isadmin=\"isAdmin\" />\n  </div>\n</template>\n\n<script>\nimport AdminPanel from \'./AdminPanel.vue\';\n\nexport default {\n  name: \'AdminAuth\',\n  components: {\n    AdminPanel\n  },\n  data() {\n    return {\n      isAdmin: false\n    };\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/AdminAuth.vue','SOURCE','F',5,'2026-02-01 20:34:45.000000'),(106,'<template>\n  <div class=\"panel-container\">\n    <AuthButton :is-admin=\"isAdmin\" />\n  </div>\n</template>\n\n<script>\nimport axios from \'axios\';\nimport AuthButton from \'./AuthButton.vue\';\n\nexport default {\n  name: \'AdminPanel\',\n  components: {\n    AuthButton\n  },\n  props: {\n    isAdmin: {\n      type: Boolean,\n      required: true\n    }\n  },\n  methods: {\n    requestAccess() {\n      axios.post(\'/api/admin/auth\')\n        .then(() => alert(\'인증 요청 전송됨\'));\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/AdminPanel.vue','SOURCE','F',5,'2026-02-01 20:34:45.000000'),(107,'<template>\n  <div>\n    <button v-if=\"isAdmin\" @click=\"requestAccess\">\n      관리자 권한 획득하기\n    </button>\n  </div>\n</template>\n\n<script>\nexport default {\n  name: \'AuthButton\',\n  props: {\n    isAdmin: {\n      type: Boolean,\n      required: true\n    },\n    onAuthClick: {\n      type: Function,\n      required: true\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/AuthButton.vue','SOURCE','F',5,'2026-02-01 20:34:45.000000'),(108,'import axios from \'axios\';\n\nconst unlockDoor = () => {\n  return axios.post(\'/api/door/unlock\');\n};','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/services/apiService.js','SOURCE','F',6,'2026-02-01 20:34:45.000000'),(109,'<template>\n  <div class=\"security-area\">\n    <p>현재 보안 등급: <strong>{{ doorStatus }}</strong></p>\n    <CircuitBoard :on-unlock=\"handleUnlock\" />\n  </div>\n</template>\n\n<script>\nimport { unlockDoor } from \'./apiService\';\nimport CircuitBoard from \'./CircuitBoard.vue\';\n\nexport default {\n  name: \'DoorControl\',\n  components: {\n    CircuitBoard\n  },\n  data() {\n    return {\n      doorStatus: \'LOCKED\'\n    };\n  },\n  watch: {\n    doorStatus(newVal) {\n      if (newVal === \'UNLOCKED\') {\n        console.log(\'출구 개방 완료\');\n        this.doorStatus = \'UNLOCKED\';\n      }\n    }\n  },\n  methods: {\n    handleUnlock() {\n      unlockDoor().then(() => {\n        this.doorStatus = \'UNLOCKED\';\n      });\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/DoorControl.vue','SOURCE','F',6,'2026-02-01 20:34:45.000000'),(110,'<template>\n  <div class=\"circuit-board\">\n    <button @click=\"onUnlock()\">회로 강제 해제</button>\n  </div>\n</template>\n\n<script>\nexport default {\n  name: \'CircuitBoard\',\n  props: {\n    onUnlock: {\n      type: Function,\n      required: true\n    }\n  }\n};\n</script>','FRONTEND','2026-02-01 20:34:45.000000','/frontend_vue/src/components/CircuitBoard.vue','SOURCE','F',6,'2026-02-01 20:34:45.000000'),(111,'import React, { useState } from \'react\';\nimport axios from \'axios\';\nimport ChipDisplay from \'./ChipDisplay\';\nimport ChipButton from \'./ChipButton\';\n\nfunction ChipControl() {\n  const [status, setStatus] = useState(\'INSTALLED\');\n\n  const handleDeactivate = () => {\n    axios.post(\'/api/chip/remove\')\n      .then(() => setStatus(\'REMOVED\'));\n  };\n\n  return (\n    <div className=\"console-panel\">\n      <ChipDisplay status={status} />\n      <ChipButton />\n    </div>\n  );\n}\n\nexport default ChipControl;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/ChipControl.jsx','SOURCE','F',1,'2026-02-01 20:41:25.000000'),(112,'import React from \'react\';\n\nfunction ChipDisplay({ currentStatus }) {\n  return (\n    <div className=\"display-area\">\n      <p>보안 칩 시스템 상태: <strong>{chipStatus}</strong></p>\n    </div>\n  );\n}\n\nexport default ChipDisplay;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/ChipDisplay.jsx','SOURCE','F',1,'2026-02-01 20:41:25.000000'),(113,'import React from \'react\';\n\nfunction ChipButton({ onDeactivate }) {\n  return (\n    <button className=\"action-btn\" onClick={onDeactivate}>\n      실험칩 비활성화\n    </button>\n  );\n}\n\nexport default ChipButton;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/ChipButton.jsx','SOURCE','F',1,'2026-02-01 20:41:25.000000'),(114,'# ? Quest 1. 서버 접속 & 실험칩 비활성화\n\n## ? 퀘스트 목표\n노트북의 관리 콘솔 화면이 여러 컴포넌트로 분리되어 있으나, 데이터 흐름이 끊겨 화면이 보이지 않는다.\n프론트엔드 컴포넌트 간의 연결 오류를 수정하여 실험칩 비활성화 시퀀스를 완료하라.\n\n## ? 요구사항\n- 컴포넌트 간 현재 칩 상태가 정상 전달되도록 수정하시오.\n- 비활성화 버튼 클릭 시 호출되는 함수가 ChipButton까지 올바르게 전달되게 하시오.\n- 비동기 통신 성공 후 REMOVED 상태가 화면에 즉시 반영되도록 하시오.','FRONTEND','2026-02-01 20:41:25.000000','/README.md','DOC','F',1,'2026-02-01 20:41:25.000000'),(115,'import React, { useState } from \'react\';\nimport AdminPanel from \'./AdminPanel\';\n\nfunction AdminAuth() {\n  const [isAdmin, setIsAdmin] = useState(false);\n\n  return (\n    <div className=\"admin-screen\">\n      <h2>중앙 제어 시스템</h2>\n      <AdminPanel isadmin={isAdmin} />\n    </div>\n  );\n}\n\nexport default AdminAuth;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/AdminAuth.jsx','SOURCE','F',2,'2026-02-01 20:41:25.000000'),(116,'import React from \'react\';\nimport axios from \'axios\';\nimport AuthButton from \'./AuthButton\';\n\nfunction AdminPanel({ isAdmin }) {\n  const requestAccess = () => {\n    axios.post(\'/api/admin/auth\').then(() => alert(\'인증 요청 전송됨\'));\n  };\n\n  return (\n    <div className=\"panel-container\">\n      <AuthButton isAdmin={isAdmin} />\n    </div>\n  );\n}\n\nexport default AdminPanel;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/AdminPanel.jsx','SOURCE','F',2,'2026-02-01 20:41:25.000000'),(117,'import React from \'react\';\n\nfunction AuthButton({ isAdmin, onAuthClick }) {\n  return (\n    <>\n      {isAdmin && (\n        <button onClick={requestAccess}>\n          관리자 권한 획득하기\n        </button>\n      )}\n    </>\n  );\n}\n\nexport default AuthButton;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/AuthButton.jsx','SOURCE','F',2,'2026-02-01 20:41:25.000000'),(118,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n관리자 인증 패널이 여러 계층의 모듈로 구성되어 있으나, 상위 제어기에서 보낸 인증 신호가 말단 실행 버튼까지 도달하지 못하고 있습니다. 컴포넌트 간의 데이터 전달 체계를 점검하여 관리자 인증 UI를 복구하십시오.\n\n## ? 요구사항\n- 시스템 초기 보안 설정이 해제되어 버튼이 아예 생성되지 않는 현상을 해결하십시오.\n- 중간 계층인 AdminPanel을 거쳐 최하단 AuthButton까지 데이터와 함수가 끊김 없이 전달되도록 수정하시오.','FRONTEND','2026-02-01 20:41:25.000000','/README.md','DOC','F',2,'2026-02-01 20:41:25.000000'),(119,'import axios from \'axios\';\n\nconst unlockDoor = () => {\n  return axios.post(\'/api/door/unlock\');\n};','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/services/apiService.js','SOURCE','F',3,'2026-02-01 20:41:25.000000'),(120,'import React, { useState, useEffect } from \'react\';\nimport { unlockDoor } from \'../services/apiService\';\nimport CircuitBoard from \'./CircuitBoard\';\n\nfunction DoorControl() {\n  const [doorStatus, setDoorStatus] = useState(\'LOCKED\');\n\n  useEffect(() => {\n    if (doorStatus === \'UNLOCKED\') {\n      console.log(\'출구 개방 완료\');\n    }\n  });\n\n  const handleUnlock = () => {\n    unlockDoor().then(() => setDoorStatus(\'UNLOCKED\'));\n  };\n\n  return (\n    <div className=\"security-area\">\n      <p>현재 보안 등급: <strong>{doorStatus}</strong></p>\n      <CircuitBoard onUnlock={handleUnlock} />\n    </div>\n  );\n}\n\nexport default DoorControl;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/DoorControl.jsx','SOURCE','F',3,'2026-02-01 20:41:25.000000'),(121,'import React from \'react\';\n\nfunction CircuitBoard({ onUnlock }) {\n  return (\n    <div className=\"circuit-board\">\n      <button onClick={onUnlock()}>회로 강제 해제</button>\n    </div>\n  );\n}\n\nexport default CircuitBoard;','FRONTEND','2026-02-01 20:41:25.000000','/frontend_react/src/components/CircuitBoard.jsx','SOURCE','F',3,'2026-02-01 20:41:25.000000'),(122,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n회로 제어 화면은 정상이나, 조작 시퀀스 실행 후 시스템이 무한 루프에 빠지거나 즉시 응답하지 않는 현상이 발생합니다. 실행 타이밍과 외부 모듈 호출 방식의 오류를 수정하여 비상 봉쇄를 해제하십시오.\n\n## ? 요구사항\n- 시스템이 특정 데이터의 변화를 감지할 때만 작동하도록 불필요한 반복 렌더링을 차단하십시오.\n- 버튼을 누르지도 않았는데 명령이 즉시 실행되어 버리는 트리거 오류를 교정하십시오.\n- 독립된 파일에 저장된 잠금 해제 프로토콜(함수)을 메인 시스템에서 인식할 수 있게 개방하십시오.','FRONTEND','2026-02-01 20:41:25.000000','/README.md','DOC','F',3,'2026-02-01 20:41:25.000000'),(123,'package com.example.demo.door;\n\nimport lombok.Getter;\nimport lombok.Setter;\nimport java.util.List;\n\n@Getter\n@Setter\npublic class CircuitPattern {\n    private List<Boolean> pattern;\n}','BACKEND','2026-02-02 10:36:38.000000','/backend_spring/src/main/java/com/example/demo/door/CircuitPattern.java','SOURCE','F',15,'2026-02-02 10:36:38.000000'),(124,'package com.example.demo.door;\n\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Getter\n@Setter\npublic class DoorVerifyRes {\n    private boolean open;\n    private String message;\n}','BACKEND','2026-02-02 10:36:38.000000','/backend_spring/src/main/java/com/example/demo/door/DoorVerifyRes.java','SOURCE','F',15,'2026-02-02 10:36:38.000000'),(125,'# ? Quest 2. 중앙 서버 권한 탈취\n\n## ? 퀘스트 목표\n관리자 인증 패널이 여러 계층의 모듈로 구성되어 있으나, 상위 제어기에서 보낸 인증 신호가 말단 실행 버튼까지 도달하지 못하고 있습니다.\n컴포넌트 간의 데이터 전달 체계를 점검하여 관리자 인증 UI를 복구하십시오.\n\n## ? 요구사항\n1. 시스템 초기 보안 설정이 해제되어 버튼이 아예 생성되지 않는 현상을 해결하십시오.\n2. 중간 계층인 AdminPanel을 거쳐 최하단 AuthButton까지 데이터와 함수가 끊김 없이 전달되도록 수정하시오.','BACKEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',5,'2026-01-30 12:09:18.000000'),(126,'# ? Quest 3. 비상 봉쇄 회로 해제\n\n## ? 퀘스트 목표\n회로 제어 화면은 정상이나, 조작 시퀀스 실행 후 시스템이 무한 루프에 빠지거나 즉시 응답하지 않는 현상이 발생합니다.\n실행 타이밍과 외부 모듈 호출 방식의 오류를 수정하여 비상 봉쇄를 해제하십시오.\n\n## ? 요구사항\n1. 시스템이 특정 데이터의 변화를 감지할 때만 작동하도록 불필요한 반복 렌더링을 차단하십시오.\n2. 버튼을 누르지도 않았는데 명령이 즉시 실행되어 버리는 트리거 오류를 교정하십시오.\n3. 독립된 파일에 저장된 잠금 해제 프로토콜(함수)을 메인 시스템에서 인식할 수 있게 개방하십시오.','FRONTEND','2026-01-30 12:09:18.000000','/README.md','DOC','F',6,'2026-01-30 12:09:18.000000'),(127,'import React, { useState } from \'react\';\nimport axios from \'axios\';\n\nfunction PowerCore() {\n  const [coreStatus, setCoreStatus] = useState(\'OFFLINE\');\n\n  const activateCore = () => {\n    axios.post(\'/api/v1/core/activate\')\n      .then(() => {\n        setCoreStaus(\'ACTIVE\');\n        alert(\'메인 코어가 활성화되었습니다!\');\n      })\n      .catch(err => {\n        console.error(\'Error:\', err);\n        alert(\'코어 활성화 실패\');\n      });\n  };\n\n  return (\n    <div className=\"power-system\">\n      <h2>메인 코어 제어 시스템</h2>\n      <p>현재 상태: <strong>{coreStatus}</strong></p>\n      <button onClick={activateCore}>메인 코어 활성화</button>\n    </div>\n  );\n}\n\nexport default PowerCore;','FRONTEND','2026-02-04 15:16:29.000000','/frontend_react/src/components/PowerCore.jsx','SOURCE','F',25,'2026-02-04 15:16:29.000000'),(128,'package io.ssafy.trycatch.domain.core.controller;\n\nimport io.ssafy.trycatch.domain.core.service.CoreService;\nimport io.ssafy.trycatch.global.common.ApiRespDto;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/v1/core\")\n@RequiredArgsConstructor\npublic class CoreController {\n\n    private final CoreService coreService;\n\n    @PostMapping(\"/activate\")\n    public ResponseEntity<ApiRespDto<String>> activateCore() {\n        coreServise.activateCore();\n        return ResponseEntity.ok(\n                ApiRespDto.success(\"메인 코어가 활성화되었습니다.\", \"ACTIVE\")\n        );\n    }\n}','BACKEND','2026-02-04 15:16:29.000000','/backend_spring/src/main/java/com/example/demo/core/CoreController.java','SOURCE','F',25,'2026-02-04 15:16:29.000000'),(129,'# ? Quest 1: 메인 코어 활성화\n\n## ? 퀘스트 목표\n심해 기지의 전원 시스템을 복구하기 위해 메인 코어를 활성화하십시오.\n\n## ? 요구사항\n버튼 클릭 시 \"메인 코어가 활성화되었습니다!\" 알림이 표시되도록 수정하시오.','FRONTEND','2026-02-04 15:16:29.000000','/README.md','DOC','F',25,'2026-02-04 15:16:29.000000'),(130,'import React, { useState } from \'react\';\nimport axios from \'axios\';\n\nfunction DroneControl() {\n  const [droneStatus, setDroneStatus] = useState(\'ACTIVE\');\n\n  const rebootDrone = () => {\n    axios.post(\'/api/v1/drone/reboot\')\n      .then(() => {\n        setDroneStatus(\'REBOOTED\');\n        alert(\'드론이 무력화되었습니다!\');\n      })\n      .catch(err => {\n        console.error(\'Error:\', err);\n        alert(\'드론 재부팅 실패\');\n      });\n  };\n\n  return (\n    <div className=\"drone-system\">\n      <h2>보안 드론 제어 시스템</h2>\n      <p>상태: <strong>{droneStauts}</strong></p>\n      <button onClick={rebootDrone}>드론 무력화</button>\n    </div>\n  );\n}\n\nexport default DroneControl;','FRONTEND','2026-02-04 15:16:29.000000','/frontend_react/src/components/DroneControl.jsx','SOURCE','F',26,'2026-02-04 15:16:29.000000'),(131,'package io.ssafy.trycatch.domain.drone.controller;\n\nimport io.ssafy.trycatch.domain.drone.service.DroneService;\nimport io.ssafy.trycatch.global.common.ApiRespDto;\nimport lombok.RequriedArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/v1/drone\")\n@RequiredArgsConstructor\npublic class DroneController {\n\n    private final DroneService droneService;\n\n    @PostMapping(\"/reboot\")\n    public ResponseEntity<ApiRespDto<String>> rebootDrone() {\n        droneService.rebootDrone();\n        return ResponseEntity.ok(\n                ApiRespDto.success(\"드론이 재부팅되었습니다.\", \"SUCCESS\")\n        );\n    }\n}','BACKEND','2026-02-04 15:16:29.000000','/backend_spring/src/main/java/com/example/demo/drone/DroneController.java','SOURCE','F',26,'2026-02-04 15:16:29.000000'),(132,'# ? Quest 2: 보안 드론 무력화\n\n## ? 퀘스트 목표\n미쳐버린 보안 드론을 무력화하기 위해 제어 시스템을 재부팅하십시오.\n\n## ? 요구사항\n- 버튼 클릭 시 \"드론이 무력화되었습니다!\" 알림이 표시되도록 수정하시오.','FRONTEND','2026-02-04 15:16:29.000000','/README.md','DOC','F',26,'2026-02-04 15:16:29.000000'),(133,'import React, { useState } from \'react\';\nimport axios from \'axios\';\n\nfunction HatchControl() {\n  const [isLocked, setIsLocked] = useState(true);\n\n  const unlockHatch = () => {\n    axios.post(\'/api/v1/hatch/unlock\')\n      .then(() => {\n        setIsLockd(false);\n        alert(\'해치가 개방되었습니다! 탈출 성공!\');\n      })\n      .catch(err => {\n        console.error(\'Error:\', err);\n        alert(\'해치 개방 실패\');\n      });\n  };\n\n  return (\n    <div className=\"hatch-system\">\n      <h2>비상 탈출구 제어 시스템</h2>\n      <p>상태: <strong>{isLocked ? \'LOCKED\' : \'UNLOCKED\'}</strong></p>\n      <button onClick={unlockHatch} disabled={!isLocked}>\n        해치 잠금 해제\n      </button>\n    </div>\n  );\n}\n\nexport default HatchControl;','FRONTEND','2026-02-04 15:16:29.000000','/frontend_react/src/components/HatchControl.jsx','SOURCE','F',27,'2026-02-04 15:16:29.000000'),(134,'package io.ssafy.trycatch.domain.hatch.controller;\n\nimport io.ssafy.trycatch.domain.hatch.service.HatchService;\nimport io.ssafy.trycatch.global.common.ApiRespDto;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.*;\n\n@RestController\n@RequestMapping(\"/api/v1/hatch\")\n@RequiredArgsConstructor\npublic class HatchController {\n\n    private final HatchService hatchService;\n\n    @PostMaping(\"/unlock\")\n    public ResponseEntity<ApiRespDto<String>> unlockHatch() {\n        hatchService.unlockHatch();\n        return ResponseEntity.ok(\n                ApiRespDto.success(\"해치가 개방되었습니다.\", \"UNLOCKED\")\n        );\n    }\n}','BACKEND','2026-02-04 15:16:29.000000','/backend_spring/src/main/java/com/example/demo/hatch/HatchController.java','SOURCE','F',27,'2026-02-04 15:16:29.000000'),(135,'# ? Quest 3. 비상 탈출구 해제\n\n## ? 퀘스트 목표\n잠긴 해치의 회로를 수정하여 탈출구를 개방하십시오.\n\n## ? 요구사항\n- 버튼 클릭 시 \"해치가 개방되었습니다! 탈출 성공!\" 알림을 표시하시오.','FRONTEND','2026-02-04 15:16:29.000000','/README.md','DOC','F',27,'2026-02-04 15:16:29.000000'),(136,'package com.example.demo.chip;\n\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Getter\n@Setter\npublic class ChipRemoveRes {\n    private String status;\n    private String message;\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/chip/ChipRemoveRes.java','SOURCE','F',16,'2026-01-30 12:09:17.000000'),(137,'package com.example.demo.admin;\n\nimport org.springframework.stereotype.Service;\nimport java.util.UUID;\n\n@Service\npublic class AdminService {\n\n    public AdminTokenRes issue() {\n        AdminTokenRes res = new AdminTokenRes();\n        res.setRole(\"ADMIN\");\n        res.setAdminToken(UUID.randomUUID().toString());\n        return res;\n    }\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminService.java','SOURCE','F',17,'2026-01-30 12:09:17.000000'),(138,'package com.example.demo.admin;\n\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Getter\n@Setter\npublic class AdminTokenRes {\n    private String role;\n    private String adminToken;\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/admin/AdminTokenRes.java','SOURCE','F',17,'2026-01-30 12:09:17.000000'),(139,'package com.example.demo.door;\n\nimport lombok.Getter;\nimport lombok.Setter;\nimport java.util.List;\n\n@Getter\n@Setter\npublic class CircuitPattern {\n    private List<Boolean> pattern;\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/CircuitPattern.java','SOURCE','F',18,'2026-01-30 12:09:17.000000'),(140,'package com.example.demo.door;\n\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Getter\n@Setter\npublic class DoorVerifyRes {\n    private boolean open;\n    private String message;\n}','BACKEND','2026-01-30 12:09:17.000000','/backend_spring/src/main/java/com/example/demo/door/DoorVerifyRes.java','SOURCE','F',18,'2026-01-30 12:09:17.000000');
