INSERT INTO `problem_framework` VALUES (1,NULL,NULL,'2026-01-30 12:09:16.000000','ReferenceError: chipStatus is not defined\nTypeError: onDeactivate is not a function',1,'F',1,'2026-01-30 12:09:16.000000'),(2,NULL,NULL,'2026-01-30 12:09:16.000000','TypeError: requestAccess is not a function\nWarning: React does not recognize the \'isadmin\' prop on a DOM element.',1,'F',2,'2026-01-30 12:09:16.000000'),(3,NULL,NULL,'2026-01-30 12:09:16.000000','Warning: Cannot update a component while rendering a different component.\nError: Too many re-renders. React limits the number of renders to prevent an infinite loop.',1,'F',3,'2026-01-30 12:09:16.000000'),(4,NULL,NULL,'2026-01-30 12:09:16.000000','[Vue warn]: Property \"chipStatus\" was accessed during render but is not defined on instance.\n[Vue warn]: Unhandled error during execution of native event handler\nTypeError: onDeactivate is not a function',2,'F',1,'2026-01-30 12:09:16.000000'),(5,NULL,NULL,'2026-01-30 12:09:16.000000','[Vue warn]: Unhandled error during execution of native event handler\nReferenceError: requestAccess is not defined\n[Vue warn]: Invalid prop: type check failed for prop \"isAdmin\". Expected Boolean, got String.',2,'F',2,'2026-01-30 12:09:16.000000'),(6,NULL,NULL,'2026-01-30 12:09:16.000000','[Vue warn]: Maximum recursive updates exceeded in component.\nThis means you have a reactive effect that is mutating its own dependencies in its computation.\n[Vue warn]: Unhandled error during execution of scheduler flush\nTypeError: unlockDoor is not a function',2,'F',3,'2026-01-30 12:09:16.000000'),(7,'[405] Method Not Allowed: POST /api/chip/remove\n[Error] ChipService.java:16: cannot find symbol \"setStatus(String)\"',3,'2026-01-30 12:09:16.000000',NULL,NULL,'F',1,'2026-01-30 12:09:16.000000'),(8,'[404] Not Found: /api/admin/steal-token (Check URL path)\n[Error] AdminController.java:18: cannot find symbol \"issue()\"',3,'2026-01-30 12:09:16.000000',NULL,NULL,'F',2,'2026-01-30 12:09:16.000000'),(9,'[Error] DoorController.java:10: variable doorService not initialized\n[400] JSON parse error: Cannot deserialize Array value into type `boolean` (Check switches field)',3,'2026-01-30 12:09:16.000000',NULL,NULL,'F',3,'2026-01-30 12:09:16.000000'),(10,'Method Not Allowed (POST): /api/chip/remove\nMethod Not Allowed: /api/chip/remove\n\n[405] POST request received but @require_GET decorator rejects it',4,'2026-01-30 12:09:16.000000',NULL,NULL,'F',1,'2026-01-30 12:09:16.000000'),(11,'Not Found: /api/admin/steal-token\n\n[404] URL pattern not found: /api/admn/ exists but /api/admin/ is not defined in urlpatterns',4,'2026-01-30 12:09:16.000000',NULL,NULL,'F',2,'2026-01-30 12:09:16.000000'),(12,'Circuit verification failed with pattern [true, false, true]\n\nExpected: open=true\nActual: open=false\n\nLogic error in verify_circuit: switches[1] == True condition prevents correct pattern match',4,'2026-01-30 12:09:16.000000',NULL,NULL,'F',3,'2026-01-30 12:09:16.000000'),(13,'org.springframework.web.HttpRequestMethodNotSupportedException: Request method \'POST\' is not supported',3,'2026-01-30 12:09:16.000000','Uncaught TypeError: Assignment to constant variable.\n    at removeChip (ChipControl.jsx:10)',1,'F',1,'2026-02-02 00:44:37.000000'),(14,'org.springframework.web.servlet.NoHandlerFoundException: No handler found for POST /api/admin/steal-token',3,'2026-01-30 12:09:16.000000','Uncaught ReferenceError: requestAccess is not defined\n    at HTMLButtonElement.onClick (AdminPanel.jsx:15)',1,'F',2,'2026-02-02 10:20:33.000000'),(15,'Required request body is missing\norg.springframework.http.converter.HttpMessageNotReadableException: Required request body is missing',3,'2026-01-30 12:09:16.000000','Warning: Cannot update a component while rendering a different component.\nError: Too many re-renders. React limits the number of renders to prevent an infinite loop.',1,'F',3,'2026-01-30 12:09:16.000000'),(16,'Request method \'POST\' is not supported\norg.springframework.web.HttpRequestMethodNotSupportedException: Request method \'POST\' is not supported',3,'2026-01-30 12:09:16.000000','Error: Property \"chipStatus\" was accessed during render but is not defined on instance.\n\nUncaught TypeError: Assignment to constant variable.\n    at removeChip (ChipControl.vue:15)',2,'F',1,'2026-01-30 12:09:16.000000'),(17,'No static resource api/admin/steal-token\norg.springframework.web.servlet.resource.NoResourceFoundException:\nNo static resource api/admin/steal-token',3,'2026-01-30 12:09:16.000000','[Vue warn]: Unhandled error during execution of native event handler\nTypeError: this.requestAccess is not a function\n    at Proxy.click (AdminPanel.vue:15)',2,'F',2,'2026-01-30 12:09:16.000000'),(18,'Required request body is missing\norg.springframework.http.converter.HttpMessageNotReadableException:\nRequired request body is missing',3,'2026-01-30 12:09:16.000000','[Vue warn]: Maximum recursive updates exceeded in component.\nThis means you have a reactive effect that is mutating its own dependencies in its computation.\nPossible sources include component template or watcher callback.',2,'F',3,'2026-01-30 12:09:16.000000'),(19,'Method Not Allowed (GET): /api/chip/remove\nMethod Not Allowed: /api/chip/remove',4,'2026-01-30 12:09:16.000000','ReferenceError: chipStatus is not defined\nTypeError: onDeactivate is not a function',1,'F',1,'2026-01-30 12:09:16.000000'),(20,'Not Found: /api/admin/steal-token\n\nNameError: name \'issue_token\' is not defined\n  File \"/app/admin/views.py\", line 8, in steal_token\n    token_data = issue_token()',4,'2026-01-30 12:09:16.000000','TypeError: requestAccess is not a function\nWarning: React does not recognize the \'isadmin\' prop on a DOM element.',1,'F',2,'2026-01-30 12:09:16.000000'),(21,'JSONDecodeError: Expecting value: line 1 column 1 (char 0)\n  File \"/app/door/views.py\", line 7, in verify_circuit\n    data = json.loads(request)',4,'2026-01-30 12:09:16.000000','Warning: Cannot update a component while rendering a different component.\nError: Too many re-renders. React limits the number of renders to prevent an infinite loop.',1,'F',3,'2026-01-30 12:09:16.000000'),(22,'Method Not Allowed (GET): /api/chip/remove/\n[ERROR]\"GET /api/chip/remove/ HTTP/1.1\" 405 0',4,'2026-01-30 12:09:16.000000','[vite] Internal server error: Assignment to constant variable.\n  at removeChip (ChipControl.vue:18:7)',2,'F',1,'2026-01-30 12:09:16.000000'),(23,'Not Found: /api/admin/steal-token/\nNameError: issue_token is not defined',4,'2026-01-30 12:09:16.000000','[Vue warn]: Extraneous non-props attributes (isadmin)\nUncaught TypeError: emit is not afunction',2,'F',2,'2026-01-30 12:09:16.000000'),(24,'JSONDecodeError\nTypeError: JSON object must be str',4,'2026-01-30 12:09:16.000000','Invalid watchsource: doorStatus\nToo many re-renders',2,'F',3,'2026-01-30 12:09:16.000000'),(25,'java: cannot find symbol\n  symbol:   variable coreServise\n  location: class io.ssafy.trycatch.domain.core.controller.CoreController',3,'2026-02-04 14:56:35.000000','ReferenceError: setCoreStaus is not defined\n    at activateCore (PowerCore.jsx:9)',1,'F',4,'2026-02-04 14:56:35.000000'),(26,'java: package lombok does not exist\nimport lombok.RequriedArgsConstructor;\n                  ^',3,'2026-02-04 14:56:35.000000','ReferenceError: droneStauts is not defined\n    at DroneControl (DroneControl.jsx:22)',1,'F',5,'2026-02-04 14:56:35.000000'),(27,'java: cannot find symbol\n  symbol: class PostMaping',3,'2026-02-04 14:56:35.000000','ReferenceError: setIsLockd is not defined\n    at unlockHatch (HatchControl.jsx:9)',1,'F',6,'2026-02-04 14:56:35.000000');
