INSERT INTO `quest_story` VALUES (1,'정신을 차리고 보니, 붉은 비상등이 켜져있는 방에서 깨어났다. 관자놀이가 타들어 가는 고통이 느껴지고, 나의 머리에 씌워진 헬멧이 폭발하기 직전인 듯 하다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/030c8541-db2d-4d13-b605-a0baa5eaa7f3_Theme1-quest1-queststory1.png','F',1,1),(2,'노트북에 뜬 화면을 보니, 어떤 오류가 발생한 것 같다. 이 곳에서 탈출하기 위해, 우선 이 에러를 해결해야 한다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/78a2dc98-8ee8-4154-8a6d-48081b359025_Theme1-quest1-queststory2.png','F',2,1),(3,'오류를 해결하자마자 옥죄던 헬멧을 바닥으로 내동댕이 쳤다. 방 밖으로 빠져나오니, 시설 전체가 비명을 지르는 듯한 모습이었다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/52343e05-8ec9-4bf1-81a4-afed9b783cf1_Theme1-quest2-queststory1.png','F',1,2),(4,'길이 보이는 대로 뛰어갔고 중앙 서버실에 도착하였고, 모니터엔 접근 권한이 없단 메시지가 떠있다. 유일한 탈출구인 지하 문을 열기 위해선, 관리자 권한을 얻어야 한다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/47729765-2656-4d26-a6f6-ace188e5ea1e_Theme1-quest2-queststory2.png','F',2,2),(5,'관리자 권한을 얻어 문을 열고, 지하 탈출구에 도달했고 문을 열어보려 했지만 열리지 않는다. 아무래도 시설 전체의 모든 문을 막아버린 것 같은데, 곧 있으면 감시자들이 나를 찾으러 올 것이다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/e71d6cdc-4be8-4afb-b864-56a6e9673da0_Theme1-quest3-queststory1.png','F',1,3),(6,'방법을 찾기 위해 살펴보니, 문의 오른쪽에 복잡하게 얽힌 회로가 보인다. 감시자들이 오기 전에 어서 이 회로를 조작해야한다.','2026-01-30 12:09:16.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/0c9e790c-cb32-41bb-a5d7-a38db9ad71ce_Theme1-quest3-queststory2.png','F',2,3),(7,'잠수정의 육중한 금속음과 함께 문이 열리자, 심해의 냉기가 온몸을 감싼다. 칠흑 같은 어둠 속에서 손전등의 가느다란 불빛만이 먼지 낀 바닥을 비출 뿐이다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/b9f1fafe-37f2-4515-afa5-2ee1d4c0b197_Theme2-quest1-queststory1.png','F',1,4),(8,'무릎까지 차오른 바닷물을 헤치며 겨우 중앙 전원실에 도달했다. 녹슨 제어반 위로 \'메인 코어\'라는 글자가 희미하게 보인다. 차가운 메인 레버를 움켜쥐는 순간, 기지의 모든 시스템이 깨어나며 숨겨진 진실이 드러날 것이다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/bbb34325-3901-4000-84c7-c6b47b6eca4a_Theme2-quest1-queststory2.png','F',2,4),(9,'전등이 깜빡거리며 켜지는 순간, 시야에 들어온 광경에 숨이 막힌다. 바닥에는 굳어버린 핏자국과 연구원들의 시체가 널브러져 있고, 공기 중에는 타버린 전선 냄새가 진동한다. 이곳의 비극은 외부가 아닌 \'내부\'에서 시작된 것이 분명하다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/12f508c7-21f7-4f57-b57b-fc562d107017_Theme2-quest2-queststory1.png','F',1,5),(10,'데이터 칩을 분리하려는 찰나, 천장에서 날카로운 기계음이 들려온다. 붉은 눈을 번뜩이며 다가오는 보안 드론의 프로펠러에는 선명한 혈흔이 묻어 있다. 살기 위해서는 저 미쳐버린 기계의 로직을 강제로 재작성해야만 한다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/f6fa01d5-c601-4206-a9ea-2ec287b58185_Theme2-quest2-queststory2.png','F',2,5),(11,'드론을 제압하자마자 날카로운 경보음과 함께 유일한 탈출구인 원형 해치가 둔탁한 소리를 내며 잠겨버린다. 산소 공급이 중단되고 기지 내부는 거대한 금속 무덤으로 변해간다. 이제 시간이 얼마 남지 않았다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/812c32d3-aa23-45e0-99c3-2a5dbaaf91d3_Theme2-quest3-queststory1.png','F',1,6),(12,'회로 차단기 패널을 뜯어내자 복잡하게 얽힌 전선들이 스파크를 일으키며 쏟아진다. 잠금장치를 해제할 유일한 방법은 이 회로 속의 오류를 찾아 연결을 수정하는 것뿐이다. 생존을 위한 마지막 디버깅이 시작된다.','2026-02-04 14:56:35.000000','https://i14e206.p.ssafy.io/api/v1/files/image/story/a10e16df-5945-48fa-b5fd-e02964f7415e_Theme2-quest3-queststory2.png','F',2,6);
/*!40000 ALTER TABLE `quest_story` ENABLE KEYS */;
UNLOCK TABLES;

